1→const InteractiveMap = ({ machines, onSelectMachine, user, selectedMachine }) => {
2→  // Helper to generate positions for the Main Block (60 machines)
3→  // Rows 1-4: 10 each, Row 5: 9, Row 6: 6, Row 7: 5 (Narrowing at bottom)
4→  const generateMainBlock = () => {
5→    const nodes = [];
6→    const rowCounts = [10, 10, 10, 10, 9, 6, 5];
7→    let currentId = 1;
8→    let startY = 150;
9→    let startX = 150;
10→    const gapX = 55;
11→    const gapY = 70;
12→
13→    rowCounts.forEach((count, rowIndex) => {
14→      const rowOffset = (10 - count) * gapX; // Right alignment: offset the left gap
15→      for (let i = 0; i < count; i++) {
16→        nodes.push({
17→          id: currentId++,
18→          x: startX + rowOffset + (i * gapX),
19→          y: startY + (rowIndex * gapY)
20→        });
21→      }
22→    });
23→    return nodes;
24→  };
25→
26→  // Helper to generate positions for the Right Block (8 machines)
27→  const generateRightBlock = () => {
28→    const nodes = [];
29→    let startY = 150;
30→    let startX = 680; // Moved even closer for compact layout
31→    const gapY = 65;
32→    for (let i = 0; i < 8; i++) {
33→      nodes.push({
34→        id: 61 + i,
35→        x: startX,
36→        y: startY + (i * gapY)
37→      });
38→    }
39→    return nodes;
40→  };
41→
42→  const allNodes = [...generateMainBlock(), ...generateRightBlock()];
43→
