49→      <div className="zone-label" style={{ top: '150px', left: '760px', transform: 'rotate(90deg)' }}>Texnolog ofisi</div>
50→      <div className="zone-label" style={{ top: '220px', left: '920px', fontSize: '0.8rem' }}>Kiyinish xonalari</div>
51→
52→      {/* Exit Markers */}
53→      <div className="chiqish-label" style={{ top: '90px', left: '260px' }}>CHIQISH</div>
54→      <div className="chiqish-label" style={{ top: '90px', left: '710px' }}>CHIQISH</div>
55→      <div className="chiqish-label" style={{ top: '90px', left: '880px' }}>CHIQISH</div>
56→
57→      {/* Machines */}
58→      {allNodes.map((node) => {
59→        const machineData = machines.find((m) => m.id === `S${node.id}`) || { baud: 0, remaining: 0 };
60→        const isConnected = machineData.baud > 0;
61→        const hasAsnova = (machineData.remaining || 0) > 0;
62→        
63→        // Status determination
64→        let statusClass = 'stopped';
